SELECT ?book ?bookLabel
WHERE {
  ?person wdt:P69 wd:Q184012.
  ?person wdt:P106 wd:Q11183023.
  ?book wdt:P50 ?person;
        wdt:P577 ?date.
  OPTIONAL { ?book rdfs:label ?bookLabel. FILTER (LANG(?bookLabel) = "en"). }
}
ORDER BY ASC(?date)
LIMIT 1

